package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.file.Path;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Mocking necessary objects
        Path path = mock(Path.class);
        File file = mock(File.class);
        Charset charset = Charset.defaultCharset();

        // Mocking behavior
        when(path.toFile()).thenReturn(file);

        // Creating CSVFormat instance
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withRecordSeparator("\r\n")
                .withIgnoreEmptyLines(false).withIgnoreSurroundingSpaces(true);

        // Invoking the print method
        CSVPrinter csvPrinter = csvFormat.print(path, charset);

        // Assertions
        assertEquals(csvPrinter.getFormat(), csvFormat);
    }
}
